<section class="section"><div class="container"><h1>Articles & Analysis</h1><?php if (!empty($articles)): ?><div class="article-list"><?php foreach ($articles as $a): ?><article class="article-card"><a href="/articles/<?= h($a['slug']) ?>"><h3><?= h($a['title']) ?></h3><?php if (!empty($a['excerpt'])): ?><p><?= h(truncate($a['excerpt'], 200)) ?></p><?php endif; ?><time><?= h(format_date($a['published_date'])) ?></time></a></article><?php endforeach; ?></div><?php else: ?><p>No articles yet.</p><?php endif; ?></div></section>
